SELECT mo.order_id AS orderId, mo.supplier_id AS supplierId, mo.order_date AS orderDate, mo.order_status AS orderStatus, mo.expected_arrived_date AS expectedArrivedDate, mo.created_by AS createdBy, mo.note,
CASE WHEN COUNT(moi.material_id) = 1 THEN MAX(m.material_name) ELSE CONCAT(MAX(m.material_name), ' 외 ', COUNT(moi.material_id) - 1, '건') END AS materialName, SUM(moi.quantity) AS totalQuantity, SUM(moi.total_price) AS totalPrice, MAX(moi.storage_location) AS storageLocation FROM material_order mo JOIN material_order_item moi ON mo.order_id = moi.order_id JOIN material m ON moi.material_id = m.material_id
(mo.order_id LIKE CONCAT('%', #{keyword}, '%') OR m.material_name LIKE CONCAT('%', #{keyword}, '%'))
AND mo.order_date >= #{startDate}
AND mo.order_date <= #{endDate}
AND mo.order_status = #{status}
GROUP BY mo.order_id
ORDER BY mo.order_id ${sortOrder}
ORDER BY mo.order_date ${sortOrder}
ORDER BY mo.expected_arrived_date ${sortOrder}
ORDER BY mo.order_date DESC
LIMIT #{pageStart}, #{perPageNum}

SELECT COUNT(DISTINCT mo.order_id)
FROM material_order mo
JOIN material_order_item moi ON mo.order_id = moi.order_id
JOIN material m ON moi.material_id = m.material_id


    (mo.order_id LIKE CONCAT('%', #{keyword}, '%')
    OR m.material_name LIKE CONCAT('%', #{keyword}, '%'))


    AND mo.order_date >= #{startDate}


    AND mo.order_date <= #{endDate}


    AND mo.order_status = #{status}
